// Phase 19f — workflow JSON shadow/safety flags (no $env; staging n8n blocks env in expressions)
const inbound = $input.first().json;
return [{
  json: {
    ...inbound,
    shadow_mode: true,
    dry_run: true,
    live_send_enabled: false,
    live_send_blocked: true
  }
}];

// Phase 19f — normalize Meta WhatsApp inbound or flat test payload for Staff API draft
// Primary: entry[0].changes[0].value.messages[0]
// Fallback: flat { client_slug, from, message_text, ... } for manual tests
// No secrets. No DB writes. No Graph API.

const raw = $input.first().json;
const body = raw.body || raw;

const entry = body.entry && body.entry[0];
const change = entry && entry.changes && entry.changes[0];
const value = (change && change.value) || body;
const messages = value.messages || [];
const msg = messages[0] || {};
const contacts = value.contacts || [];
const profile = (contacts[0] && contacts[0].profile) || {};

const clientSlug = String(body.client_slug || 'wolfhouse-somo').trim();
const channel = 'whatsapp';
const from = String(msg.from || body.from || body.phone || '').trim();
const waMessageId = String(msg.id || body.wa_message_id || '').trim() || null;
const messageText = String(
  (msg.text && msg.text.body) || body.message_text || body.text || body.message || ''
).trim();
const guestName = String(profile.name || body.guest_name || body.name || '').trim() || null;
const timestamp = msg.timestamp || body.timestamp || null;
const language = body.language != null ? String(body.language).trim() : null;

if (!messageText) {
  throw new Error('Missing required field: message_text (Meta messages[0].text.body or flat message_text)');
}

return [{
  json: {
    client_slug: clientSlug,
    channel,
    from,
    phone: from,
    wa_message_id: waMessageId,
    message_text: messageText,
    guest_name: guestName,
    timestamp,
    language,
    source: 'luna_whatsapp_pipe_shadow',
    shadow_mode: true,
    dry_run: true,
    live_send_enabled: false,
    live_send_blocked: true
  }
}];

// Phase 19f — map draft -> send payload + stable idempotency_key
// Primary key: luna:{client_slug}:{wa_message_id}:{send_kind}
// Fallback (manual/test only): luna:{client_slug}:{from}:{timestamp_or_hash}:{send_kind}

const api = $input.first().json;
const normalized = $('Code - Normalize WhatsApp Inbound').first().json;
const se = api.send_eligibility || {};
const nextAction = api.next_action || null;
const suggestedReply = api.suggested_reply || null;

const SEND_KIND_MAP = {
  ask_missing_field: 'ask_missing_field',
  show_quote: 'show_quote'
};
const BLOCKED_ACTIONS = new Set([
  'checkin_day', 'handoff', 'handoff_to_staff', 'unsupported', 'staff_required', 'risky'
]);

let sendKind = se.allowed_send_kind || null;
if (!sendKind && nextAction && SEND_KIND_MAP[nextAction]) {
  sendKind = SEND_KIND_MAP[nextAction];
}

const requiresStaff = se.requires_staff === true;
const handoffBlocked = requiresStaff
  || BLOCKED_ACTIONS.has(nextAction)
  || sendKind === 'checkin_day'
  || !sendKind
  || !['ask_missing_field', 'show_quote'].includes(sendKind);

let idempotencyKey = null;
if (sendKind && !handoffBlocked) {
  const waId = normalized.wa_message_id;
  if (waId) {
    idempotencyKey = `luna:${normalized.client_slug}:${waId}:${sendKind}`;
  } else {
    // Fallback for manual tests only when wa_message_id absent
    const ts = normalized.timestamp || Date.now();
    const hash = String(ts).slice(-10);
    idempotencyKey = `luna:${normalized.client_slug}:${normalized.from}:${hash}:${sendKind}`;
  }
}

const sendEligible = !handoffBlocked
  && se.auto_send_ready === true
  && !requiresStaff
  && !!suggestedReply
  && !!idempotencyKey;

const sendPayload = sendEligible ? {
  client_slug: normalized.client_slug,
  to: normalized.from,
  idempotency_key: idempotencyKey,
  send_kind: sendKind,
  suggested_reply: suggestedReply,
  source: 'guest_reply_draft',
  draft: api,
  send_eligibility: se
} : null;

return [{
  json: {
    draft_success: api.success !== false,
    suggested_reply: suggestedReply,
    next_action: nextAction,
    send_eligibility: se,
    send_kind: sendKind,
    idempotency_key: idempotencyKey,
    send_eligible: sendEligible,
    send_attempted: false,
    requires_staff: requiresStaff,
    handoff_blocked: handoffBlocked,
    client_slug: normalized.client_slug,
    to: normalized.from,
    from: normalized.from,
    wa_message_id: normalized.wa_message_id,
    draft: api,
    source: 'guest_reply_draft',
    send_payload: sendPayload,
    shadow_mode: normalized.shadow_mode,
    dry_run: normalized.dry_run,
    live_send_enabled: false,
    live_send_blocked: true
  }
}];

// Phase 19f — map Staff API guest-reply-send response to debug output
const sendResp = $input.first().json;
const built = $('Code - Build Send Payload').first().json;
const sr = sendResp.body || sendResp;

return [{
  json: {
    shadow_mode: true,
    dry_run: built.dry_run,
    live_send_enabled: false,
    live_send_blocked: built.live_send_blocked,
    draft_success: built.draft_success,
    suggested_reply: built.suggested_reply,
    next_action: built.next_action,
    send_eligibility: built.send_eligibility,
    send_kind: built.send_kind,
    idempotency_key: built.idempotency_key,
    wa_message_id: built.wa_message_id,
    send_attempted: true,
    send_performed: sr.send_performed === true,
    sends_whatsapp: sr.sends_whatsapp === true,
    duplicate: sr.duplicate === true,
    idempotent_replay: sr.idempotent_replay === true,
    blocked_reasons: sr.blocked_reasons || [],
    whatsapp_message_id: sr.whatsapp_message_id || null,
    requires_staff: built.requires_staff,
    staff_api_draft_endpoint: '/staff/bot/guest-reply-draft',
    staff_api_send_endpoint: '/staff/bot/guest-reply-send',
    note: 'Phase 19f: pipe shadow — send route called when eligible; Staff API owns send decision.'
  }
}];

// Phase 19f — draft-only path: handoff/risky/unsupported/requires_staff skips guest-reply-send
const built = $input.first().json;

const blockedReasons = [];
if (built.requires_staff) blockedReasons.push('requires_staff');
if (built.handoff_blocked) blockedReasons.push('handoff_or_blocked');
if (!built.suggested_reply) blockedReasons.push('missing_suggested_reply');
if (!built.send_eligible) blockedReasons.push('send_not_eligible');

return [{
  json: {
    shadow_mode: true,
    dry_run: built.dry_run,
    live_send_enabled: false,
    live_send_blocked: true,
    draft_success: built.draft_success,
    suggested_reply: built.suggested_reply,
    next_action: built.next_action,
    send_eligibility: built.send_eligibility,
    send_kind: built.send_kind,
    idempotency_key: built.idempotency_key,
    wa_message_id: built.wa_message_id,
    send_attempted: false,
    send_performed: false,
    sends_whatsapp: false,
    duplicate: false,
    idempotent_replay: false,
    blocked_reasons: blockedReasons,
    whatsapp_message_id: null,
    requires_staff: built.requires_staff,
    staff_api_draft_endpoint: '/staff/bot/guest-reply-draft',
    staff_api_send_endpoint: null,
    note: 'Phase 19f: send route skipped — handoff/risky/not eligible; requires_staff true does not call guest-reply-send.'
  }
}];
